#include<bits/stdc++.h>
#define int long long
using namespace std;
int n,a,b,w[2005],dp[2005][2005],maxx;
signed main()
{
	cin>>n>>a>>b;
	for(int i=1;i<=n;i++) cin>>w[i];
	for(int i=1;i<=n;i++)
		for(int j=a;j>=0;j--)
			for(int k=b;k>=0;k--)
			{
				if(j>=w[i]) dp[j][k]=max(dp[j][k],dp[j-w[i]][k]+w[i]);
				if(k>=w[i]) dp[j][k]=max(dp[j][k],dp[j][k-w[i]]+w[i]);
				maxx=max(maxx,dp[j][k]);
			}
	cout<<maxx;
	return 0;
}
